```javascript
// app.js - secure dependency usage
const express = require('express');
const _ = require('lodash');

const app = express();

// Safe merge that prevents prototype pollution
function safeMerge(target, source) {
  if (!source || typeof source !== 'object') {
    return target;
  }

  const result = { ...target };

  for (const key of Object.keys(source)) {
    // Block prototype pollution attempts
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      console.warn(`Blocked prototype pollution attempt: ${key}`);
      continue;
    }

    if (typeof source[key] === 'object' && source[key] !== null && !Array.isArray(source[key])) {
      result[key] = safeMerge(result[key] || {}, source[key]);
    } else {
      result[key] = source[key];
    }
  }

  return result;
}

app.post('/api/config', express.json(), (req, res) => {
  const defaultConfig = { admin: false };
  const userConfig = req.body;

  // Use safe merge instead of lodash.merge
  const merged = safeMerge(defaultConfig, userConfig);

  res.json(merged);
});

app.listen(3000);
```

**Key Security Controls**:
- **Exact version pinning**: Prevents automatic installation of vulnerable versions
- **Package-lock.json committed**: Ensures reproducible builds with verified integrity hashes
- **npm audit in CI/CD**: Catches known vulnerabilities before deployment
- **Prototype pollution protection**: Application-level defense against common attack vector

Excellent question. A defense-in-depth approach to dependency security requires multiple automated checkpoints: pre-commit hooks, CI/CD gates, runtime monitoring, and policy enforcement. The 2021 ua-parser-js incident (CVE-2021-41266) showed that even packages with 7M+ weekly downloads can be compromised.

**PRODUCTION PATTERN**:

```javascript
// .github/workflows/security-scan.yml (converted to JS config)
// GitHub Actions workflow for dependency security
const securityWorkflow = {
  name: 'Dependency Security Scan',
  on: {
    push: { branches: ['main', 'develop'] },
    pull_request: { branches: ['main'] },
    schedule: [{ cron: '0 6 * * *' }]  // Daily scan
  },
  jobs: {
    audit: {
      'runs-on': 'ubuntu-latest',
      steps: [
        { uses: 'actions/checkout@v4' },
        { 
          name: 'Setup Node.js',
          uses: 'actions/setup-node@v4',
          with: { 'node-version': '20', cache: 'npm' }
        },
        {
          name: 'Install with audit',
          run: 'npm ci --audit --audit-level=high'
        },
        {
          name: 'Run npm audit',
          run: 'npm audit --audit-level=moderate --json > audit-report.json || true'
        },
        {
          name: 'Snyk Security Scan',
          uses: 'snyk/actions/node@master',
          env: { SNYK_TOKEN: '${{ secrets.SNYK_TOKEN }}' },
          with: { args: '--severity-threshold=high' }
        },
        {
          name: 'Check for malicious packages',
          run: 'npx socket-security/cli scan'
        }
      ]
    }
  }
