// security/json-parser-safe.js
/**
 * Custom JSON parser that prevents prototype pollution
 */
function safeJsonParse(jsonString) {
  return JSON.parse(jsonString, (key, value) => {
    if (DANGEROUS_KEYS.includes(key)) {
      return undefined; // Remove dangerous keys
    }
    return value;
  });
}

/**
 * Express body parser replacement
 */
function safeBodyParser() {
  return (req, res, next) => {
    if (req.headers['content-type'] === 'application/json') {
      let body = '';

      req.on('data', chunk => {
        body += chunk.toString();
        // Limit body size
        if (body.length > 1e6) {
          req.destroy();
          res.status(413).json({ error: 'Payload too large' });
        }
      });

      req.on('end', () => {
        try {
          req.body = safeJsonParse(body);
          next();
        } catch (e) {
          res.status(400).json({ error: 'Invalid JSON' });
        }
      });
    } else {
      next();
    }
  };
}

module.exports = { safeJsonParse, safeBodyParser };
