    },
    "config": {
        "optimize-autoloader": false
    }
}
*/

// Insecure deployment: vendor directory accessible from web
// DocumentRoot /var/www/html (includes /vendor)

// Using outdated Guzzle with SSRF vulnerability
require_once 'vendor/autoload.php';

use GuzzleHttp\Client;

class WebhookService {
    private $client;

    public function __construct() {
        // Using Guzzle 6.x with known SSRF issues
        $this->client = new Client([
            'timeout' => 30,
            'verify' => false  // SSL verification disabled!
        ]);
