POST /webhook?url=http://169.254.169.254/latest/meta-data/iam/security-credentials/

# Access internal Redis
POST /webhook?url=http://localhost:6379/
```

**Why This Is Dangerous**:
- PHPUnit dev dependency exposed in production allows arbitrary code execution
- Wildcard version constraints (*) pull any version including vulnerable ones
- Guzzle 6.x has known SSRF vulnerabilities (CVE-2022-31043)
- Disabled SSL verification enables man-in-the-middle attacks
- Vendor directory accessible from web exposes sensitive files

**SECURE VERSION**:

```php
<?php
// secure-composer.json
/*
{
    "name": "myapp/webshop",
    "require": {
        "guzzlehttp/guzzle": "^7.8.1",
        "symfony/http-foundation": "^6.4",
        "monolog/monolog": "^3.5"
    },
    "require-dev": {
        "phpunit/phpunit": "^10.5"
    },
    "config": {
        "optimize-autoloader": true,
        "sort-packages": true,
        "allow-plugins": {
            "php-http/discovery": false
        }
    },
    "scripts": {
        "check-security": "composer audit"
    }
}
*/

require_once 'vendor/autoload.php';

use GuzzleHttp\Client;
use GuzzleHttp\Exception\GuzzleException;
use Psr\Log\LoggerInterface;

class SecureWebhookService {
    private Client $client;
    private LoggerInterface $logger;
    private array $allowedHosts;

    public function __construct(LoggerInterface $logger, array $allowedHosts) {
        $this->logger = $logger;
        $this->allowedHosts = $allowedHosts;

        // Secure Guzzle configuration
        $this->client = new Client([
            'timeout' => 10,
            'connect_timeout' => 5,
            'verify' => true,  // SSL verification enabled
            'allow_redirects' => [
                'max' => 3,
                'strict' => true,
                'protocols' => ['https']  // HTTPS only
            ]
        ]);
    }

    public function sendWebhook(string $url, array $data): bool {
        // Validate URL to prevent SSRF
        if (!$this->isAllowedUrl($url)) {
            $this->logger->warning('Blocked webhook to unauthorized URL', [
                'url' => $url
            ]);
            return false;
        }

        try {
            $response = $this->client->post($url, [
                'json' => $data,
                'headers' => [
                    'User-Agent' => 'MyApp-Webhook/1.0'
                ]
            ]);

            $this->logger->info('Webhook sent successfully', [
                'url' => $url,
                'status' => $response->getStatusCode()
            ]);

            return $response->getStatusCode() >= 200 && 
                   $response->getStatusCode() < 300;
        } catch (GuzzleException $e) {
            $this->logger->error('Webhook failed', [
                'url' => $url,
                'error' => $e->getMessage()
            ]);
            return false;
        }
    }

    private function isAllowedUrl(string $url): bool {
        $parsed = parse_url($url);

        if (!$parsed || !isset($parsed['host'])) {
            return false;
        }

        // Block internal/private IPs
        $ip = gethostbyname($parsed['host']);
        if ($this->isPrivateIP($ip)) {
            return false;
        }

        // Check against allowlist
        return in_array($parsed['host'], $this->allowedHosts, true);
    }

    private function isPrivateIP(string $ip): bool {
        return filter_var($ip, FILTER_VALIDATE_IP, 
            FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE) === false;
    }
}
```

**Key Security Controls**:
- **Dev dependencies separated**: PHPUnit in require-dev, not deployed to production
- **Pinned versions**: Specific version constraints prevent unexpected updates
- **SSL verification enabled**: Prevents MITM attacks on outbound requests
- **SSRF protection**: URL allowlisting and private IP blocking
- **Composer audit**: Built-in security scanning in CI/CD pipeline

Automating dependency security requires multiple layers of protection including CI/CD integration, runtime monitoring, and emergency response capabilities.

**PRODUCTION PATTERN**:

```php
<?php
// DependencySecurityManager.php
declare(strict_types=1);

namespace App\Security;

use Psr\Log\LoggerInterface;
use Symfony\Component\Cache\Adapter\RedisAdapter;
use Symfony\Contracts\Cache\ItemInterface;

class DependencySecurityManager {
    private LoggerInterface $logger;
    private RedisAdapter $cache;
    private array $config;
    private const CACHE_TTL = 3600;
    private const ADVISORY_API = 'https://packagist.org/api/security-advisories/';

    public function __construct(
        LoggerInterface $logger,
        RedisAdapter $cache,
        array $config
    ) {
        $this->logger = $logger;
        $this->cache = $cache;
        $this->config = $config;
    }

    /**
     * Runtime dependency vulnerability check
     */
    public function checkRuntimeVulnerabilities(): array {
        $installedPackages = $this->getInstalledPackages();
        $vulnerabilities = [];

        foreach ($installedPackages as $package => $version) {
            $advisories = $this->getAdvisories($package);

            foreach ($advisories as $advisory) {
                if ($this->isVersionAffected($version, $advisory)) {
                    $vulnerabilities[] = [
                        'package' => $package,
                        'installed_version' => $version,
                        'advisory' => $advisory['advisoryId'],
                        'cve' => $advisory['cve'] ?? 'N/A',
                        'severity' => $advisory['severity'] ?? 'unknown',
                        'title' => $advisory['title'],
                        'affected_versions' => $advisory['affectedVersions']
                    ];
                }
            }
        }

        if (!empty($vulnerabilities)) {
            $this->handleVulnerabilities($vulnerabilities);
        }

        return $vulnerabilities;
    }

    private function getInstalledPackages(): array {
        $lockFile = $this->config['project_root'] . '/composer.lock';

        if (!file_exists($lockFile)) {
            throw new \RuntimeException('composer.lock not found');
        }

        $lockData = json_decode(file_get_contents($lockFile), true);
        $packages = [];

        foreach ($lockData['packages'] ?? [] as $package) {
            $packages[$package['name']] = $package['version'];
        }

        return $packages;
    }

    private function getAdvisories(string $package): array {
        return $this->cache->get(
            'advisories_' . md5($package),
            function (ItemInterface $item) use ($package): array {
                $item->expiresAfter(self::CACHE_TTL);

                $client = new \GuzzleHttp\Client([
                    'timeout' => 10,
                    'verify' => true
                ]);

                try {
                    $response = $client->post(self::ADVISORY_API, [
                        'json' => ['packages' => [$package]]
                    ]);

                    $data = json_decode($response->getBody()->getContents(), true);
                    return $data['advisories'][$package] ?? [];
                } catch (\Exception $e) {
                    $this->logger->warning('Failed to fetch advisories', [
                        'package' => $package,
                        'error' => $e->getMessage()
                    ]);
                    return [];
                }
            }
        );
    }

    private function isVersionAffected(string $version, array $advisory): bool {
        // Use Composer semver to check version constraints
        $versionParser = new \Composer\Semver\VersionParser();
        $constraint = $versionParser->parseConstraints(
            $advisory['affectedVersions']
        );

        return $constraint->matches(
            new \Composer\Semver\Constraint\Constraint('=', $version)
        );
    }

    private function handleVulnerabilities(array $vulnerabilities): void {
        $criticalCount = 0;
        $highCount = 0;

        foreach ($vulnerabilities as $vuln) {
            $severity = strtolower($vuln['severity']);

            if ($severity === 'critical') {
                $criticalCount++;
            } elseif ($severity === 'high') {
                $highCount++;
            }

            $this->logger->critical('Vulnerable dependency detected', $vuln);
        }

        // Alert on critical vulnerabilities
        if ($criticalCount > 0) {
            $this->sendSecurityAlert($vulnerabilities, 'CRITICAL');

            // Optional: Trigger circuit breaker for affected functionality
            if ($this->config['auto_disable_on_critical']) {
                $this->enableCircuitBreaker($vulnerabilities);
            }
        }

        // Emit metrics for monitoring
        $this->emitMetrics($criticalCount, $highCount, count($vulnerabilities));
    }

    private function sendSecurityAlert(array $vulnerabilities, string $level): void {
        // Integration with PagerDuty/OpsGenie/Slack
        $alertPayload = [
            'severity' => $level,
            'title' => 'Vulnerable Dependencies Detected',
            'vulnerabilities' => $vulnerabilities,
            'environment' => $this->config['environment'],
            'timestamp' => date('c')
        ];

        // Send to alerting system
        if ($this->config['pagerduty_key']) {
            $this->sendPagerDutyAlert($alertPayload);
        }

        $this->logger->emergency('Security alert sent', $alertPayload);
    }

    private function enableCircuitBreaker(array $vulnerabilities): void {
        // Disable affected features temporarily
        $affectedPackages = array_column($vulnerabilities, 'package');

        $this->cache->get('circuit_breaker_packages', function (ItemInterface $item) 
            use ($affectedPackages): array {
            $item->expiresAfter(86400); // 24 hours
            return $affectedPackages;
        });

        $this->logger->warning('Circuit breaker enabled for packages', [
            'packages' => $affectedPackages
        ]);
    }

    private function emitMetrics(int $critical, int $high, int $total): void {
        // StatsD/Prometheus metrics
        if (class_exists('\Prometheus\CollectorRegistry')) {
            $registry = \Prometheus\CollectorRegistry::getDefault();

            $gauge = $registry->getOrRegisterGauge(
                'app',
                'vulnerable_dependencies_total',
                'Number of vulnerable dependencies',
                ['severity']
            );

            $gauge->set($critical, ['critical']);
            $gauge->set($high, ['high']);
            $gauge->set($total - $critical - $high, ['other']);
        }
    }

    private function sendPagerDutyAlert(array $payload): void {
        // PagerDuty integration
        $client = new \GuzzleHttp\Client();
        $client->post('https://events.pagerduty.com/v2/enqueue', [
            'json' => [
                'routing_key' => $this->config['pagerduty_key'],
                'event_action' => 'trigger',
                'payload' => [
                    'summary' => $payload['title'],
                    'severity' => strtolower($payload['severity']),
                    'source' => $this->config['environment'],
                    'custom_details' => $payload
                ]
            ]
        ]);
    }
}
