```yaml
# .github/workflows/security.yml - CI/CD Integration
name: Dependency Security Scan

on:
  push:
    branches: [main, develop]
  pull_request:
  schedule:
    - cron: '0 */6 * * *'  # Every 6 hours

jobs:
  security-audit:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Setup PHP
        uses: shivammathur/setup-php@v2
        with:
          php-version: '8.3'
          tools: composer:v2

      - name: Install dependencies
        run: composer install --no-dev --prefer-dist

      - name: Composer Audit
        run: composer audit --format=json > audit-results.json
        continue-on-error: true

      - name: Local PHP Security Checker
        uses: symfonycorp/security-checker-action@v5

      - name: Roave Security Advisories Check
        run: composer require --dev roave/security-advisories:dev-latest

      - name: Check for exposed vendor files
        run: |
          if [ -f "public/vendor/autoload.php" ]; then
            echo "ERROR: Vendor directory exposed in public folder!"
            exit 1
          fi

      - name: Upload audit results
        uses: actions/upload-artifact@v4
        with:
          name: security-audit
          path: audit-results.json

      - name: Fail on critical vulnerabilities
        run: |
          CRITICAL=$(jq '.advisories | map(select(.severity == "critical")) | length' audit-results.json)
          if [ "$CRITICAL" -gt 0 ]; then
            echo "Critical vulnerabilities found!"
            exit 1
          fi
